@Component({
  selector: 'app-users',
  standalone: true,
  template: `{{ users.length }}`
})
export class UsersComponent {
  users: any[] = [];

  constructor(private http: HttpClient) {}

  ngOnInit() {
    this.http
      .get<any[]>('https://jsonplaceholder.typicode.com/users')
      .subscribe(users => {
        this.users = users;
      });
